import { app, BrowserWindow, dialog, ipcMain, clipboard, Menu } from 'electron';
import fs from 'fs';
import path from 'path';
import Excel from 'exceljs';
import { CellValue } from 'exceljs'; // Adjust import based on your library
import { DataErrorHandler } from './dataInput';
import { Camp } from './camp';
import { Kids } from './kids';
import { Schedule } from './schedule';

// This allows TypeScript to pick up the magic constants that's auto-generated by Forge's Webpack
// plugin that tells the Electron app where to look for the Webpack-bundled app code (depending on
// whether you're running in development or production).
declare const MAIN_WINDOW_WEBPACK_ENTRY: string;
declare const MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY: string;

let CAMP_BEST_SCHEDULE: Schedule | null = null;

// Handle creating/removing shortcuts on Windows when installing/uninstalling.
if (require('electron-squirrel-startup')) {
  app.quit();
}

const createWindow = (): void => {
  // Create the browser window.
  const mainWindow = new BrowserWindow({
    height: 1000,
    minHeight: 650,
    width: 1200,
    minWidth: 650,
    show: false,
    backgroundColor: '#f6d25f',
    // fallback icon if wix doesn't provide the icon during make file
    icon: path.join(__dirname, '../assets/icons/sheriff-badge-msi.ico'),
    webPreferences: {
      preload: MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY,
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: false,
    },
  });

  // and load the index.html of the app.
  mainWindow.loadURL(MAIN_WINDOW_WEBPACK_ENTRY);

  // Check if the entry URL points to a local network development port (Webpack Dev Server)
  if (MAIN_WINDOW_WEBPACK_ENTRY.startsWith('http://')) {
    // 1. Listen for the native ready-to-show event to handle clean window display
    mainWindow.once('ready-to-show', () => {
      // 2. Wrap your development safety-net refresh inside the event lifecycle
      setTimeout(() => {
        mainWindow.webContents.reloadIgnoringCache();
        mainWindow.show();
        mainWindow.focus();
      }, 600); // Retains your dev fallback but guarantees rendering layers have parsed first
    });
  } else {
    // Production Mode / Playwright Automation Testing Environments:
    // Display seamlessly the instant background rendering nodes conclude calculations
    mainWindow.once('ready-to-show', () => {
      mainWindow.show();
      mainWindow.focus();
    });
  }

  // Open file Dialog for user to pick file.
  ipcMain.handle('open-file-dialog', async () => {
    const result = await dialog.showOpenDialog({
      properties: ['openFile'],
      filters: [{ name: 'Sheets', extensions: ['xlsx'] }],
    });

    const workbook = new Excel.Workbook();
    await workbook.xlsx.readFile(result.filePaths[0]);

    let worksheet = workbook.worksheets[0];
    const sheetCount = workbook.worksheets.length;
    if (worksheet !== undefined && sheetCount > 1) {
      const targetSheet = workbook.worksheets.find(ws => ws.name.toLowerCase().includes('campers'));
      if (targetSheet) {
        const worksheet = workbook.getWorksheet(targetSheet.name);
      }
    }
    let firstNameCol = -1;
    let lastNameCol = -1;
    let landActivity1Col = -1;
    let landActivity2Col = -1;
    let landActivity3Col = -1;
    let waterActivity1Col = -1;
    let waterActivity2Col = -1;
    let waterActivity3Col = -1;

    const row = worksheet.getRow(1);
    const values = row.values as CellValue[];
    const worksheetLength = values.length;
    if (typeof worksheetLength === "number") {
      for (let i = 1; i < worksheetLength; i++) {
        const cell = values[i];
        if (cell !== undefined && typeof cell === 'string') {
          const cellContent = cell.toLowerCase();
          if (cellContent.includes('first name')) {
            firstNameCol = i;
          } else if (cellContent.includes('last name')) {
            lastNameCol = i;
          } else if (cellContent.includes('l1')) {
            landActivity1Col = i;
          } else if (cellContent.includes('l2')) {
            landActivity2Col = i;
          } else if (cellContent.includes('l3')) {
            landActivity3Col = i;
          } else if (cellContent.includes('w1')) {
            waterActivity1Col = i;
          } else if (cellContent.includes('w2')) {
            waterActivity2Col = i;
          } else if (cellContent.includes('w3')) {
            waterActivity3Col = i;
          }
        }
      }
    }


    const activityData: string[][] = [];
    let firstName = '';
    let lastName = '';
    let landActivity1 = '';
    let landActivity2 = '';
    let landActivity3 = '';
    let waterActivity1 = '';
    let waterActivity2 = '';
    let waterActivity3 = '';
    worksheet.eachRow({ includeEmpty: true }, function (row) {
      const firstNameCell = row.getCell( firstNameCol );
      if (firstNameCell.type === Excel.ValueType.String) {
        firstName = firstNameCell.value as string;
      }
      const lastNameCell = row.getCell( lastNameCol );
      if (lastNameCell.type === Excel.ValueType.String) {
        lastName = lastNameCell.value as string;
      }
      const landActivity1Cell = row.getCell( landActivity1Col );
      if (landActivity1Cell.type === Excel.ValueType.String) {
        const landActivity = landActivity1Cell.value as string;
        landActivity1 = landActivity.toLowerCase();
      }
      const landActivity2Cell = row.getCell( landActivity2Col );
      if (landActivity2Cell.type === Excel.ValueType.String) {
        const landActivity = landActivity2Cell.value as string;
        landActivity2 = landActivity.toLowerCase();
      }
      const landActivity3Cell = row.getCell( landActivity3Col );
      if (landActivity3Cell.type === Excel.ValueType.String) {
        const landActivity = landActivity3Cell.value as string;
        landActivity3 = landActivity.toLowerCase();
      }
      const waterActivity1Cell = row.getCell( waterActivity1Col );
      if (waterActivity1Cell.type === Excel.ValueType.String) {
        const waterActivity = waterActivity1Cell.value as string;
        waterActivity1 = waterActivity.toLowerCase();
      }
      const waterActivity2Cell = row.getCell( waterActivity2Col );
      if (waterActivity2Cell.type === Excel.ValueType.String) {
        const waterActivity = waterActivity2Cell.value as string;
        waterActivity2 = waterActivity.toLowerCase();
      }
      const waterActivity3Cell = row.getCell( waterActivity3Col );
      if (waterActivity3Cell.type === Excel.ValueType.String) {
        const waterActivity = waterActivity3Cell.value as string;
        waterActivity3 = waterActivity.toLowerCase();
      }
      activityData.push([firstName, lastName, landActivity1, landActivity2, landActivity3, waterActivity1, waterActivity2, waterActivity3]);
    });

    const activityDataWithoutHeader = activityData.slice(1);
    const { allErrors, dataErrors } = handleErrors(activityDataWithoutHeader);
    if (!allErrors.every(item => item === false)) {
      mainWindow.webContents.send('error-list', JSON.stringify(dataErrors.getErrorList()));
    } else {
      const result = scheduleKids(activityDataWithoutHeader);
      if (result) {
        mainWindow.webContents.send('result-list', JSON.stringify(result));
      } else {
        mainWindow.webContents.send(
          'error-list',
          JSON.stringify([
            {
              header: 'Unable to schedule kids',
              errorList: [
                'This is most likely due to way too many kids making the same choice or there are not enough total kids attending.',
              ],
            },
          ])
        );
      }
    }
  });

  // Handle input via the pastebox
  ipcMain.handle('submit-text', async (event, data) => {
    const { allErrors, dataErrors } = handleErrors(data);
    if (!allErrors.every(item => item === false)) {
      mainWindow.webContents.send('error-list', JSON.stringify(dataErrors.getErrorList()));
    } else {
      const result = scheduleKids(data);
      if (result) {
        mainWindow.webContents.send('result-list', JSON.stringify(result));
      } else {
        mainWindow.webContents.send(
          'error-list',
          JSON.stringify([
            {
              header: 'Unable to schedule kids',
              errorList: [
                'This is most likely due to way too many kids making the same choice or there are not enough total kids attending.',
              ],
            },
          ])
        );
      }
    }
  });

  ipcMain.handle('copy-schedule', async (event, data) => {
    clipboard.writeText(data);
    mainWindow.webContents.send('clipboard-content', 'notification-box');
  });

  ipcMain.handle(
    'export-excel',
    async (event, result, waterActs: string[], land9amActs: string[], land10amActs: string[]) => {
      const workbook = new Excel.Workbook();
      const activityWS = workbook.addWorksheet('By Activity');

      // Define columns (optional but recommended for object-based row addition)
      activityWS.columns = [
        { header: 'Activity Time', key: 'time', width: 15 },
        { header: 'Activity', key: 'activity', width: 12 },
        { header: 'Kid Count', key: 'count', width: 10 },
        { header: 'Names', key: 'names', width: 200 },
      ];

      const allActivities = waterActs.concat(waterActs, land9amActs, land10amActs);
      const activityTimes = Array(waterActs.length)
        .fill('Water 9AM')
        .concat(
          Array(waterActs.length).fill('Water 10AM'),
          Array(land9amActs.length).fill('Land 9AM'),
          Array(land10amActs.length).fill('Land 10AM')
        );

      // Add data rows
      for (let i = 0; i < allActivities.length; i++) {
        const timeSlot = activityTimes[i].toLowerCase().replaceAll(' ', '');
        const kids = result[timeSlot][allActivities[i]];
        const kidsCount = kids.length;
        activityWS.addRow({
          time: activityTimes[i],
          activity: allActivities[i],
          count: kidsCount,
          names: joinNames(kids),
        });
      }

      const nameWS = workbook.addWorksheet('By Name');

      // Define columns (optional but recommended for object-based row addition)
      nameWS.columns = [
        { header: 'Name', key: 'name', width: 25 },
        { header: 'Water Time', key: 'waterTime', width: 15 },
        { header: 'Water Activity', key: 'waterActivity', width: 12 },
        { header: 'Land Time', key: 'landTime', width: 15 },
        { header: 'Land Activity', key: 'landActivity', width: 12 },
      ];

      for (const name of result.kids.names.sort()) {
        if (!CAMP_BEST_SCHEDULE) {
          continue; // Skip or handle missing schedule data appropriately
        }
        let waterTime = '10am';
        let waterActivity = CAMP_BEST_SCHEDULE.schedule.get(name)?.['timeSlots']['water10am'];
        if (CAMP_BEST_SCHEDULE.schedule.get(name)?.['timeSlots']['water9am'] !== null) {
          waterTime = '9am';
          waterActivity = CAMP_BEST_SCHEDULE.schedule.get(name)?.['timeSlots']['water9am'];
        }
        let landTime = '10am';
        let landActivity = CAMP_BEST_SCHEDULE.schedule.get(name)?.['timeSlots']['land10am'];
        if (CAMP_BEST_SCHEDULE.schedule.get(name)?.['timeSlots']['land9am'] !== null) {
          landTime = '9am';
          landActivity = CAMP_BEST_SCHEDULE.schedule.get(name)?.['timeSlots']['land9am'];
        }

        nameWS.addRow({
          name: name,
          waterTime: waterTime,
          waterActivity: waterActivity,
          landTime: landTime,
          landActivity: landActivity,
        });
      }

      const buffer = await workbook.xlsx.writeBuffer();
      const { filePath, canceled } = await dialog.showSaveDialog({
        title: 'Save NY Kids Camp Workbook',
        filters: [{ name: 'Excel Files', extensions: ['xlsx'] }],
      });
      if (!canceled && filePath) {
        fs.writeFileSync(filePath, buffer as unknown as Uint8Array);
      }
    }
  );
  // Open the DevTools.
  // mainWindow.webContents.openDevTools();
};

const joinNames = (names: string[]): string => {
  if (names.length === 0) {
    return 'No kids scheduled';
  }
  let nameOrder = '';
  names.forEach(name => {
    const [last, first] = name.split(/\s+/);
    const inOrder = `${first} ${last}, `;
    nameOrder += inOrder;
  });
  return nameOrder.slice(0, -2);
};

const scheduleKids = (data: string[][]) => {
  const kids = new Kids(data);
  const camp = new Camp(kids);
  camp.scheduleTheKids(1000);
  CAMP_BEST_SCHEDULE = camp.bestSchedule;
  return camp.bestSchedule;
};

const handleErrors = (data: string[][]) => {
  // const { campData, headerRow } = dataParser(data);
  const dataErrors = new DataErrorHandler(data, false);
  const allErrors: boolean[] = [
    // dataErrors.numOfFields(),
    dataErrors.wrongActivity(),
    dataErrors.notEnoughKids(),
    dataErrors.tooManyKids(),
    dataErrors.duplicateName(),
    // dataErrors.duplicateChoice(),
  ];
  return { allErrors, dataErrors };
};

Menu.setApplicationMenu(null);

// This method will be called when Electron has finished
// initialization and is ready to create browser windows.
// Some APIs can only be used after this event occurs.
app.on('ready', createWindow);

// Quit when all windows are closed, except on macOS. There, it's common
// for applications and their menu bar to stay active until the user quits
// explicitly with Cmd + Q.
app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit();
  }
});

app.on('activate', () => {
  // On OS X it's common to re-create a window in the app when the
  // dock icon is clicked and there are no other windows open.
  if (BrowserWindow.getAllWindows().length === 0) {
    createWindow();
  }
});

